#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PI 3.1415926535897932
#define M 2147483647
#define A 1103515245
#define C 12345

inline double randu(__global int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs((double)seed[index] / (double)M);
}

inline double randn(__global int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

inline double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < 0.5)
        return (double)newValue;
    else
        return (double)(newValue + 1);
}

__kernel void likelihood_kernel(
    __global double *arrayX,
    __global double *arrayY,
    __global double *xj,
    __global double *yj,
    __global double *CDF,
    __global int *ind,
    __global int *objxy,
    __global double *likelihood,
    __global uchar *I,
    __global double *u,
    __global double *weights,
    const int Nparticles,
    const int countOnes,
    const int max_size,
    const int k,
    const int IszY,
    const int Nfr,
    __global int *seed,
    __global double *partial_sums,
    __local double *local_sums)
{
    int gid = get_global_id(0);
    if (gid >= Nparticles) return;

    // Update positions with noise
    double x_pos = arrayX[gid] + 1.0 + 5.0 * randn(seed, gid);
    double y_pos = arrayY[gid] - 2.0 + 2.0 * randn(seed, gid);
    xj[gid] = x_pos;
    yj[gid] = y_pos;

    // Compute likelihood
    double sum_likelihood = 0.0;
    int base_idx = gid * countOnes;
    for (int y = 0; y < countOnes; y++) {
        int indX = (int)roundDouble(x_pos) + objxy[y * 2 + 1];
        int indY = (int)roundDouble(y_pos) + objxy[y * 2];
        int idx = indX * IszY * Nfr + indY * Nfr + k;
        if (idx < 0 || idx >= max_size) idx = 0;
        ind[base_idx + y] = idx;
        uchar val = I[idx];
        sum_likelihood += ((val - 100) * (val - 100) - (val - 228) * (val - 228)) / 50.0;
    }
    likelihood[gid] = sum_likelihood / (double)countOnes;

    // Update weights with exp(likelihood)
    weights[gid] = weights[gid] * exp(likelihood[gid]);

    // Store partial sums for reduction
    local_sums[get_local_id(0)] = weights[gid];
    barrier(CLK_LOCAL_MEM_FENCE);

    // Parallel reduction in local memory
    int local_size = get_local_size(0);
    for (int offset = local_size / 2; offset > 0; offset >>= 1) {
        if (get_local_id(0) < offset) {
            local_sums[get_local_id(0)] += local_sums[get_local_id(0) + offset];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write partial sum to global memory
    if (get_local_id(0) == 0) {
        partial_sums[get_group_id(0)] = local_sums[0];
    }
}

__kernel void sum_kernel(
    __global double *partial_sums,
    const int Nparticles)
{
    int gid = get_global_id(0);
    if (gid != 0) return;

    double total = 0.0;
    for (int i = 0; i < Nparticles; i++) {
        total += partial_sums[i];
    }
    partial_sums[0] = total;
}

__kernel void normalize_weights_kernel(
    __global double *weights,
    const int Nparticles,
    __global double *partial_sums,
    __global double *CDF,
    __global double *u,
    __global int *seed)
{
    int gid = get_global_id(0);
    if (gid >= Nparticles) return;

    double sumWeights = partial_sums[0];
    weights[gid] = weights[gid] / sumWeights;

    // Compute CDF
    barrier(CLK_GLOBAL_MEM_FENCE);
    if (gid == 0) {
        CDF[0] = weights[0];
        for (int i = 1; i < Nparticles; i++) {
            CDF[i] = CDF[i - 1] + weights[i];
        }
    }
    barrier(CLK_GLOBAL_MEM_FENCE);

    // Compute u array for resampling
    if (gid == 0) {
        double u1 = (1.0 / (double)Nparticles) * randu(seed, 0);
        for (int i = 0; i < Nparticles; i++) {
            u[i] = u1 + (double)i / (double)Nparticles;
        }
    }
}

inline int findIndex(__global double *CDF, int lengthCDF, double value) {
    int index = -1;
    for (int x = 0; x < lengthCDF; x++) {
        if (value <= CDF[x]) {
            index = x;
            break;
        }
    }
    if (index == -1) {
        return lengthCDF - 1;
    }
    return index;
}

__kernel void find_index_kernel(
    __global double *arrayX,
    __global double *arrayY,
    __global double *CDF,
    __global double *u,
    __global double *xj,
    __global double *yj,
    __global double *weights,
    const int Nparticles)
{
    int gid = get_global_id(0);
    if (gid >= Nparticles) return;

    int i = findIndex(CDF, Nparticles, u[gid]);
    if (i == -1) i = Nparticles - 1;
    xj[gid] = arrayX[i];
    yj[gid] = arrayY[i];
    weights[gid] = 1.0 / (double)Nparticles;
}
